package com.enterprise.app.repository;

import com.enterprise.app.entity.Transaction;
import com.enterprise.app.entity.TransactionStatus;
import com.enterprise.app.entity.TransactionType;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.Optional;

@Repository
public interface TransactionRepository extends JpaRepository<Transaction, Long> {
    
    Optional<Transaction> findByTransactionRef(String transactionRef);
    
    List<Transaction> findByUserId(Long userId);
    
    List<Transaction> findByStatus(TransactionStatus status);
    
    List<Transaction> findByType(TransactionType type);
    
    @Query("SELECT t FROM Transaction t WHERE t.user.id = :userId AND t.status = :status")
    List<Transaction> findByUserIdAndStatus(@Param("userId") Long userId, @Param("status") TransactionStatus status);
    
    @Query("SELECT t FROM Transaction t WHERE t.user.id = :userId AND t.createdAt BETWEEN :startDate AND :endDate")
    List<Transaction> findByUserIdAndDateRange(@Param("userId") Long userId, 
                                                @Param("startDate") LocalDateTime startDate, 
                                                @Param("endDate") LocalDateTime endDate);
    
    @Query("SELECT SUM(t.amount) FROM Transaction t WHERE t.user.id = :userId AND t.status = :status")
    BigDecimal sumAmountByUserIdAndStatus(@Param("userId") Long userId, @Param("status") TransactionStatus status);
    
    @Query("SELECT t FROM Transaction t WHERE t.amount >= :minAmount AND t.amount <= :maxAmount")
    List<Transaction> findByAmountRange(@Param("minAmount") BigDecimal minAmount, @Param("maxAmount") BigDecimal maxAmount);
    
    @Query("SELECT t FROM Transaction t JOIN FETCH t.user WHERE t.id = :id")
    Optional<Transaction> findByIdWithUser(@Param("id") Long id);
    
    List<Transaction> findByCreatedAtBetween(LocalDateTime startDate, LocalDateTime endDate);
}

// src/main/java/com/enterprise/app/service/UserService.java
package com.enterprise.app.service;

import com.enterprise.app.dto.UserCreateDTO;
import com.enterprise.app.dto.UserResponseDTO;
import com.enterprise.app.dto.UserUpdateDTO;
import com.enterprise.app.entity.User;
import com.enterprise.app.exception.ResourceNotFoundException;
import com.enterprise.app.exception.UserAlreadyExistsException;
import com.enterprise.app.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class UserService {
    
    private final UserRepository userRepository;
    
    @Transactional
    public UserResponseDTO createUser(UserCreateDTO createDTO) {
        if (userRepository.existsByUsername(createDTO.getUsername())) {
            throw new UserAlreadyExistsException("Username already exists: " + createDTO.getUsername());
        }
        
        if (userRepository.existsByEmail(createDTO.getEmail())) {
            throw new UserAlreadyExistsException("Email already exists: " + createDTO.getEmail());
        }
        
        User user = User.builder()
                .username(createDTO.getUsername())
                .email(createDTO.getEmail())
                .password(createDTO.getPassword())
                .firstName(createDTO.getFirstName())
                .lastName(createDTO.getLastName())
                .active(true)
                .build();
        
        User savedUser = userRepository.save(user);
        return mapToResponseDTO(savedUser);
    }
    
    public UserResponseDTO getUserById(Long id) {
        User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User not found with id: " + id));
        return mapToResponseDTO(user);
    }
    
    public UserResponseDTO getUserByUsername(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new ResourceNotFoundException("User not found with username: " + username));
        return mapToResponseDTO(user);
    }
    
    public List<UserResponseDTO> getAllUsers() {
        return userRepository.findAll().stream()
                .map(this::mapToResponseDTO)
                .collect(Collectors.toList());
    }
    
    public List<UserResponseDTO> getActiveUsers() {
        return userRepository.findByActiveTrue().stream()
                .map(this::mapToResponseDTO)
                .collect(Collectors.toList());
    }
    
    @Transactional
    public UserResponseDTO updateUser(Long id, UserUpdateDTO updateDTO) {
        User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User not found with id: " + id));
        
        if (updateDTO.getEmail() != null && !updateDTO.getEmail().equals(user.getEmail())) {
            if (userRepository.existsByEmail(updateDTO.getEmail())) {
                throw new UserAlreadyExistsException("Email already exists: " + updateDTO.getEmail());
            }
            user.setEmail(updateDTO.getEmail());
        }
        
        if (updateDTO.getFirstName() != null) {
            user.setFirstName(updateDTO.getFirstName());
        }
        
        if (updateDTO.getLastName() != null) {
            user.setLastName(updateDTO.getLastName());
        }
        
        if (updateDTO.getActive() != null) {
            user.setActive(updateDTO.getActive());
        }
        
        User updatedUser = userRepository.save(user);
        return mapToResponseDTO(updatedUser);
    }
    
    @Transactional
    public void deleteUser(Long id) {
        if (!userRepository.existsById(id)) {
            throw new ResourceNotFoundException("User not found with id: " + id);
        }
        userRepository.deleteById(id);
    }
    
    @Transactional
    public void deactivateUser(Long id) {
        User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User not found with id: " + id));
        user.setActive(false);
        userRepository.save(user);
    }
    
    public List<UserResponseDTO> searchUsersByName(String name) {
        return userRepository.searchByName(name).stream()
                .map(this::mapToResponseDTO)
                .collect(Collectors.toList());
    }
    
    private UserResponseDTO mapToResponseDTO(User user) {
        return UserResponseDTO.builder()
                .id(user.getId())
                .username(user.getUsername())
                .email(user.getEmail())
                .firstName(user.getFirstName())
                .lastName(user.getLastName())
                .active(user.getActive())
                .createdAt(user.getCreatedAt())
                .updatedAt(user.getUpdatedAt())
                .build();
    }
}

// src/main/java/com/enterprise/app/service/TransactionService.java
package com.enterprise.app.service;

import com.enterprise.app.dto.TransactionCreateDTO;
import com.enterprise.app.dto.TransactionResponseDTO;
import com.enterprise.app.dto.TransactionUpdateDTO;
import com.enterprise.app.entity.Transaction;
import com.enterprise.app.entity.TransactionStatus;
import com.enterprise.app.entity.User;
import com.enterprise.app.exception.ResourceNotFoundException;
import com.enterprise.app.repository.TransactionRepository;
import com.enterprise.app.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;
import java.util.UUID;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class TransactionService {
    
    private final TransactionRepository transactionRepository;
    private final UserRepository userRepository;
    
    @Transactional
    public TransactionResponseDTO createTransaction(TransactionCreateDTO createDTO) {
        User user = userRepository.findById(createDTO.getUserId())
                .orElseThrow(() -> new ResourceNotFoundException("User not found with id: " + createDTO.getUserId()));
        
        Transaction transaction = Transaction.builder()
                .transactionRef(generateTransactionRef())
                .amount(createDTO.getAmount())
                .currency(createDTO.getCurrency())
                .description(createDTO.getDescription())
                .type(createDTO.getType())
                .status(TransactionStatus.PENDING)
                .user(user)
                .build();
        
        Transaction savedTransaction = transactionRepository.save(transaction);
        return mapToResponseDTO(savedTransaction);
    }
    
    public TransactionResponseDTO getTransactionById(Long id) {
        Transaction transaction = transactionRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction not found with id: " + id));
        return mapToResponseDTO(transaction);
    }
    
    public TransactionResponseDTO getTransactionByRef(String transactionRef) {
        Transaction transaction = transactionRepository.findByTransactionRef(transactionRef)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction not found with ref: " + transactionRef));
        return mapToResponseDTO(transaction);
    }
    
    public List<TransactionResponseDTO> getAllTransactions() {
        return transactionRepository.findAll().stream()
                .map(this::mapToResponseDTO)
                .collect(Collectors.toList());
    }
    
    public List<TransactionResponseDTO> getTransactionsByUserId(Long userId) {
        return transactionRepository.findByUserId(userId).stream()
                .map(this::mapToResponseDTO)
                .collect(Collectors.toList());
    }
    
    public List<TransactionResponseDTO> getTransactionsByStatus(TransactionStatus status) {
        return transactionRepository.findByStatus(status).stream()
                .map(this::mapToResponseDTO)
                .collect(Collectors.toList());
    }
    
    public List<TransactionResponseDTO> getTransactionsByUserIdAndStatus(Long userId, TransactionStatus status) {
        return transactionRepository.findByUserIdAndStatus(userId, status).stream()
                .map(this::mapToResponseDTO)
                .collect(Collectors.toList());
    }
    
    public List<TransactionResponseDTO> getTransactionsByDateRange(Long userId, LocalDateTime startDate, LocalDateTime endDate) {
        return transactionRepository.findByUserIdAndDateRange(userId, startDate, endDate).stream()
                .map(this::mapToResponseDTO)
                .collect(Collectors.toList());
    }
    
    public BigDecimal getTotalAmountByUserIdAndStatus(Long userId, TransactionStatus status) {
        BigDecimal total = transactionRepository.sumAmountByUserIdAndStatus(userId, status);
        return total != null ? total : BigDecimal.ZERO;
    }
    
    @Transactional
    public TransactionResponseDTO updateTransactionStatus(Long id, TransactionUpdateDTO updateDTO) {
        Transaction transaction = transactionRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction not found with id: " + id));
        
        transaction.setStatus(updateDTO.getStatus());
        
        if (updateDTO.getStatus() == TransactionStatus.COMPLETED || 
            updateDTO.getStatus() == TransactionStatus.FAILED) {
            transaction.setProcessedAt(LocalDateTime.now());
        }
        
        Transaction updatedTransaction = transactionRepository.save(transaction);
        return mapToResponseDTO(updatedTransaction);
    }
    
    @Transactional
    public TransactionResponseDTO processTransaction(Long id) {
        Transaction transaction = transactionRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction not found with id: " + id));
        
        transaction.setStatus(TransactionStatus.PROCESSING);
        transactionRepository.save(transaction);
        
        try {
            transaction.setStatus(TransactionStatus.COMPLETED);
            transaction.setProcessedAt(LocalDateTime.now());
        } catch (Exception e) {
            transaction.setStatus(TransactionStatus.FAILED);
            transaction.setProcessedAt(LocalDateTime.now());
        }
        
        Transaction processedTransaction = transactionRepository.save(transaction);
        return mapToResponseDTO(processedTransaction);
    }
    
    @Transactional
    public void cancelTransaction(Long id) {
        Transaction transaction = transactionRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("Transaction not found with id: " + id));
        
        if (transaction.getStatus() == TransactionStatus.COMPLETED) {
            throw new IllegalStateException("Cannot cancel completed transaction");
        }
        
        transaction.setStatus(TransactionStatus.CANCELLED);
        transaction.setProcessedAt(LocalDateTime.now());
        transactionRepository.save(transaction);
    }
    
    private String generateTransactionRef() {
        return "TXN-" + UUID.randomUUID().toString().toUpperCase();
    }
    
    private TransactionResponseDTO mapToResponseDTO(Transaction transaction) {
        return TransactionResponseDTO.builder()
                .id(transaction.getId())
                .transactionRef(transaction.getTransactionRef())
                .amount(transaction.getAmount())
                .currency(transaction.getCurrency())
                .description(transaction.getDescription())
                .status(transaction.getStatus())
                .type(transaction.getType())
                .userId(transaction.getUser().getId())
                .createdAt(transaction.getCreatedAt())
                .updatedAt(transaction.getUpdatedAt())
                .processedAt(transaction.getProcessedAt())
                .build();
    }
}

