package com.enterprise.app.controller;

import com.enterprise.app.dto.TransactionCreateDTO;
import com.enterprise.app.dto.TransactionResponseDTO;
import com.enterprise.app.dto.TransactionUpdateDTO;
import com.enterprise.app.entity.TransactionStatus;
import com.enterprise.app.service.TransactionService;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;

@RestController
@RequestMapping("/api/transactions")
@RequiredArgsConstructor
public class TransactionController {
    
    private final TransactionService transactionService;
    
    @PostMapping
    public ResponseEntity<TransactionResponseDTO> createTransaction(@Valid @RequestBody TransactionCreateDTO createDTO) {
        TransactionResponseDTO transaction = transactionService.createTransaction(createDTO);
        return new ResponseEntity<>(transaction, HttpStatus.CREATED);
    }
    
    @GetMapping("/{id}")
    public ResponseEntity<TransactionResponseDTO> getTransactionById(@PathVariable Long id) {
        TransactionResponseDTO transaction = transactionService.getTransactionById(id);
        return ResponseEntity.ok(transaction);
    }
    
    @GetMapping("/ref/{transactionRef}")
    public ResponseEntity<TransactionResponseDTO> getTransactionByRef(@PathVariable String transactionRef) {
        TransactionResponseDTO transaction = transactionService.getTransactionByRef(transactionRef);
        return ResponseEntity.ok(transaction);
    }
    
    @GetMapping
    public ResponseEntity<List<TransactionResponseDTO>> getAllTransactions() {
        List<TransactionResponseDTO> transactions = transactionService.getAllTransactions();
        return ResponseEntity.ok(transactions);
    }
    
    @GetMapping("/user/{userId}")
    public ResponseEntity<List<TransactionResponseDTO>> getTransactionsByUserId(@PathVariable Long userId) {
        List<TransactionResponseDTO> transactions = transactionService.getTransactionsByUserId(userId);
        return ResponseEntity.ok(transactions);
    }
    
    @GetMapping("/status/{status}")
    public ResponseEntity<List<TransactionResponseDTO>> getTransactionsByStatus(@PathVariable TransactionStatus status) {
        List<TransactionResponseDTO> transactions = transactionService.getTransactionsByStatus(status);
        return ResponseEntity.ok(transactions);
    }
    
    @GetMapping("/user/{userId}/status/{status}")
    public ResponseEntity<List<TransactionResponseDTO>> getTransactionsByUserIdAndStatus(
            @PathVariable Long userId, @PathVariable TransactionStatus status) {
        List<TransactionResponseDTO> transactions = transactionService.getTransactionsByUserIdAndStatus(userId, status);
        return ResponseEntity.ok(transactions);
    }
    
    @GetMapping("/user/{userId}/date-range")
    public ResponseEntity<List<TransactionResponseDTO>> getTransactionsByDateRange(
            @PathVariable Long userId,
            @RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) LocalDateTime startDate,
            @RequestParam @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME) LocalDateTime endDate) {
        List<TransactionResponseDTO> transactions = transactionService.getTransactionsByDateRange(userId, startDate, endDate);
        return ResponseEntity.ok(transactions);
    }
    
    @GetMapping("/user/{userId}/total")
    public ResponseEntity<BigDecimal> getTotalAmount(@PathVariable Long userId, @RequestParam TransactionStatus status) {
        BigDecimal total = transactionService.getTotalAmountByUserIdAndStatus(userId, status);
        return ResponseEntity.ok(total);
    }
    
    @PutMapping("/{id}/status")
    public ResponseEntity<TransactionResponseDTO> updateTransactionStatus(
            @PathVariable Long id, @Valid @RequestBody TransactionUpdateDTO updateDTO) {
        TransactionResponseDTO transaction = transactionService.updateTransactionStatus(id, updateDTO);
        return ResponseEntity.ok(transaction);
    }
    
    @PostMapping("/{id}/process")
    public ResponseEntity<TransactionResponseDTO> processTransaction(@PathVariable Long id) {
        TransactionResponseDTO transaction = transactionService.processTransaction(id);
        return ResponseEntity.ok(transaction);
    }
    
    @PostMapping("/{id}/cancel")
    public ResponseEntity<Void> cancelTransaction(@PathVariable Long id) {
        transactionService.cancelTransaction(id);
        return ResponseEntity.noContent().build();
    }
}

